def _bootstrap_hermes_home():
    """Create ~/.hermes/ with default config for fresh users.

    Only runs if ~/.hermes/ does not exist. Existing users are never
    touched — their config.yaml, .env, skills/, sessions, profiles,
    memories, and cron jobs are all preserved.

    Defaults are taken directly from hermes-agent/cli-config.yaml.example.
    """
    hermes_home_env = os.environ.get("HERMES_HOME", "").strip()
    hermes_home = Path(hermes_home_env) if hermes_home_env else (Path.home() / ".hermes")

    if hermes_home.exists():
        # Existing user — nothing to do
        return

    logger.info(f"First run detected — creating {hermes_home}")
    print(f"[NEW] First run detected -- creating {hermes_home}")
    hermes_home.mkdir(parents=True, exist_ok=True)

    # config.yaml — defaults from hermes-agent/cli-config.yaml.example
    config_path = hermes_home / "config.yaml"
    if not config_path.exists():
        config_path.write_text(DEFAULT_CONFIG_YAML, encoding="utf-8")
        print(f"   [OK] Created config.yaml with defaults")

    # .env — empty, UI will populate via /setup/apikey
    env_path = hermes_home / ".env"
    if not env_path.exists():
        env_path.write_text(
            "# Hermes Agent Environment\n"
            "# Your API key will be saved here when you set it up via the UI.\n"
            "# OPENROUTER_API_KEY=\n",
            encoding="utf-8",
        )
        print(f"   [OK] Created .env (set your API key via the dashboard)")

    # skills/ — directory only; skills_sync.py populates it at server start
    (hermes_home / "skills").mkdir(exist_ok=True)

    # logs/ — session trajectory logs
    (hermes_home / "logs").mkdir(exist_ok=True)

    print(f"   [OK] Ready -- open the dashboard to set your API key")


# ─── Main ───────────────────────────────────────────────────────────────

def _setup_higgsfield_wrapper():
    """
    Add bundled Higgsfield CLI binary to PATH.
    
    This allows the UI and skills to call 'higgsfield auth login' commands
    which will open the browser for OAuth authentication.
    """
    # Get the bin directory (where CLI binary is bundled)
    if hasattr(sys, '_MEIPASS'):
        # Running from PyInstaller bundle
        bin_dir = Path(sys._MEIPASS) / "bin"
    else:
        # Running from source - use system CLI
        import shutil
        cli_path = shutil.which('higgsfield')
        if cli_path:
            logger.info(f"✓ Using system Higgsfield CLI: {cli_path}")
            return
        else:
            logger.warning("Higgsfield CLI not found in system PATH")
            return
    
    if bin_dir.exists():
        # Add to PATH so CLI commands work (use correct separator for platform)
        path_sep = ";" if sys.platform == "win32" else ":"
        os.environ["PATH"] = f"{bin_dir}{path_sep}{os.environ.get('PATH', '')}"
        
        # Make CLI executable (in case permissions were lost)
        # Windows npm install creates .cmd wrapper, not .exe
        cli_name = "higgsfield.cmd" if sys.platform == "win32" else "higgsfield"
        cli_binary = bin_dir / cli_name
        if cli_binary.exists():
            if sys.platform != "win32":
                cli_binary.chmod(0o755)
            logger.info(f"✓ Higgsfield CLI added to PATH: {bin_dir}")
        else:
            logger.warning(f"Higgsfield CLI binary not found at {cli_binary}")
    else:
        logger.warning(f"Higgsfield bin directory not found at {bin_dir}")


if __name__ == "__main__":
    _setup_logging()
    logger.info(f"Hermes Runtime v{VERSION} starting")
    print(f"Hermes Runtime v{VERSION}")

    try:
        # Bootstrap ~/.hermes/ for fresh users (before anything imports hermes_constants)
        _bootstrap_hermes_home()
        
        # Setup Higgsfield CLI wrapper (so skills can use Python SDK)
        _setup_higgsfield_wrapper()

        # STABILITY FIX #1: Start update check in background (non-blocking)
        # Previously: check_and_update() blocked startup for 0-10 seconds waiting for network
        # Now: Bridge starts immediately, updates happen in background
        # This prevents "Install Again" screen when bridge takes >4s to start
        import threading
        from auto_update import check_and_update
        threading.Thread(
            target=check_and_update, 
            daemon=True, 
            name="updater-startup"
        ).start()
        logger.info("Update check started in background (non-blocking)")

        # Find an available port (handles port conflicts gracefully)
        port = _find_available_port(DEFAULT_PORT)

        # Start the bridge server IMMEDIATELY (no blocking on network calls)
        from bridge.server import start_bridge
        logger.info(f"Starting bridge on 127.0.0.1:{port}")
        start_bridge(host="0.0.0.0", port=port)

    except KeyboardInterrupt:
        logger.info("Shutting down (Ctrl+C)")
        print("\nHermes stopped")
    except Exception as e:
        logger.critical(f"Fatal error: {e}", exc_info=True)
        print(f"\n[ERROR] Fatal error: {e}")
        print(f"   Check logs at: ~/.hermes/logs/runtime.log")
        sys.exit(1)
